import { RepoType } from '../contract.js';

export const checkId = 'health-check';
export const name = 'Health Check Route';
export const appliesTo = ['deployable', 'server', 'framework'];

const HEALTH_PATTERNS = [
  /\b(healthz?|health[-_]?check|status|ready|alive|live|ping|up)\b/i,
  /livenessProbe|readinessProbe|startupProbe/i,
  /['"`]\/health\b/i,
  /['"`]\/status\b/i,
  /['"`]\/ready\b/i,
  /['"`]\/alive\b/i,
  /['"`]\/ping\b/i,
  /get\s*\(\s*['"`]\/health/i,
  /app\.(get|use|route|all)\s*\(\s*['"`]\/health/i,
  /router\.(get|use|all)\s*\(\s*['"`]\/health/i,
  /event\.(path|node\.req\.url).*\bhealth\b/i,
  /defineEventHandler.*\bhealth\b/i,
  /HealthCheck\b/,
  /under-pressure|terminus|lightship/i,
];

const SERVER_DEPS = new Set([
  'express', 'fastify', 'koa', 'restify', 'polka', 'connect', 'hapi', '@hapi/hapi',
  'micro', 'http-server', 'serve-static', 'json-server', 'next', 'nuxt', 'astro',
  '@astrojs/node', 'remix', '@remix-run/node', '@remix-run/serve', '@sveltejs/kit',
  'nitropack', 'nitro', 'h3', 'hono', 'elysia', '@nestjs/core', '@nestjs/common',
  '@nestjs/platform-express', '@nestjs/platform-fastify', 'cloudflare',
  '@cloudflare/workers-types', 'wrangler', 'worktop', 'itty-router',
]);

const HEALTH_LIBS = new Set([
  '@nestjs/terminus', 'lightship', 'terminus', 'express-actuator',
  '@godaddy/terminus', 'under-pressure', 'prom-client',
]);

function hasServerDependency(packageJson) {
  if (!packageJson) return false;
  const deps = { ...packageJson.dependencies, ...packageJson.devDependencies, ...packageJson.peerDependencies };
  return Object.keys(deps).some(d => SERVER_DEPS.has(d));
}

function findHealthDependency(packageJson) {
  if (!packageJson) return null;
  const deps = { ...packageJson.dependencies, ...packageJson.devDependencies, ...packageJson.peerDependencies };
  return Object.keys(deps).find(d => HEALTH_LIBS.has(d)) || null;
}

function hasDeploymentConfig(tree) {
  return tree.some(p => {
    const lower = p.toLowerCase();
    return /^dockerfile/.test(lower) ||
      /^docker-compose\.(yml|yaml)/.test(lower) ||
      /^wrangler\.(toml|json)/.test(lower) ||
      /^serverless\.(yml|yaml|json|ts)/.test(lower) ||
      /^fly\.toml/.test(lower) ||
      /^Procfile/.test(lower) ||
      /^app\.(ya?ml)/.test(lower) ||
      /^captain-definition/.test(lower) ||
      /(^|\/)k8s\//.test(p) ||
      /(^|\/)kubernetes\//.test(p) ||
      /(^|\/)helm\//.test(p);
  });
}

function hasServerCode(tree, packageJson) {
  if (hasServerDependency(packageJson)) return true;
  if (hasDeploymentConfig(tree)) return true;

  const serverPathRe = /(^|\/)((src\/)?(api|server|routes|middleware|controllers|handlers|backend|workers|functions|netlify\/functions|supabase\/functions|edge-functions))\//i;
  if (tree.some(p => serverPathRe.test(p))) return true;

  if (tree.some(p => /^(src\/)?(server|app|index|main)\.(js|ts|mjs|cjs)$/.test(p))) return true;

  if (packageJson?.scripts) {
    const s = packageJson.scripts;
    if (s.start || s.serve || s.deploy || s.preview || s['start:prod']) return true;
  }

  return false;
}

function isStaticSite(tree, packageJson) {
  if (!packageJson) return false;
  const deps = { ...packageJson.dependencies, ...packageJson.devDependencies };
  const hasFramework = ['next', 'nuxt', 'astro', 'gatsby', 'vue', 'react', 'svelte', '@sveltejs/kit'].some(f => f in deps);
  const hasApiDir = tree.some(p => /(^|\/)((src\/)?api|pages\/api|app\/api|server\/api|routes|server|middleware|controllers|handlers|backend|workers|functions)\//.test(p));
  const hasServer = hasServerDependency(packageJson) || tree.some(p => /^(src\/)?(server|app|index|main)\.(js|ts|mjs|cjs)$/.test(p));
  return hasFramework && !hasApiDir && !hasServer;
}

function scoreFile(path) {
  let score = 0;
  const lower = path.toLowerCase();
  const basename = lower.split('/').pop();

  if (/^(server|app|index|main)\.(js|ts|mjs|cjs)$/.test(basename)) score += 20;
  if (/\.(route|router|server|controller|handler|endpoint|middleware)\./.test(basename)) score += 8;
  if (/(^|\/)api\//.test(lower)) score += 15;
  if (/(^|\/)pages\/api\//.test(lower)) score += 18;
  if (/(^|\/)app\/api\//.test(lower)) score += 18;
  if (/(^|\/)server\/api\//.test(lower)) score += 18;
  if (/(^|\/)routes?\//.test(lower)) score += 12;
  if (/(^|\/)server\//.test(lower)) score += 10;
  if (/(^|\/)controllers?\//.test(lower)) score += 8;
  if (/(^|\/)handlers?\//.test(lower)) score += 6;
  if (/(^|\/)middleware\//.test(lower)) score += 6;
  if (/(^|\/)backend\//.test(lower)) score += 6;
  if (/(^|\/)workers?\//.test(lower)) score += 8;
  if (/(^|\/)functions\//.test(lower)) score += 8;
  if (/(^|\/)apps?\/[^/]+\/(api|server|routes|middleware|controllers|handlers)\//.test(lower)) score += 10;
  if (/(^|\/)packages\/[^/]+\/(api|server|routes|middleware|controllers|handlers)\//.test(lower)) score += 8;

  if (path.startsWith('src/')) score += 3;

  if (/\.(test|spec)\./i.test(path)) score -= 20;
  if (/(__tests__|__mocks__|fixtures?|examples?|demo|playground|benchmark|docs|\.github|\.storybook|scripts|dist|build|coverage|storybook|bin|cli|config|vitest|jest|knip|lint|\.vscode)\//i.test(path)) score -= 15;
  if (/node_modules/.test(path)) score -= 30;
  if (/\.d\.ts$/.test(path)) score -= 20;

  const depth = path.split('/').length;
  if (depth > 6) score -= 2;
  if (depth > 10) score -= 5;

  return score;
}

export async function check(context) {
  const { tree, files, packageJson, repoType } = context;

  try {
    if (repoType === RepoType.LIBRARY || repoType === RepoType.EMPTY) {
      return {
        checkId,
        status: 'not-applicable',
        confidence: 'high',
        message: 'Library or empty repository — no health route needed',
        findings: [],
      };
    }

    if (repoType === 'framework') {
      const scripts = packageJson?.scripts || {};
      const hasAppSignals = scripts.start || scripts.serve || scripts.deploy || scripts.preview ||
        scripts['start:prod'] ||
        hasDeploymentConfig(tree) ||
        hasServerDependency(packageJson) ||
        tree.some(p => /^apps\/[^/]+\/(api|server|routes|middleware)/i.test(p));

      if (!hasAppSignals) {
        return {
          checkId,
          status: 'not-applicable',
          confidence: 'high',
          message: 'Framework source repository without deployed application signals',
          findings: [],
        };
      }
    }

    if (!hasServerCode(tree, packageJson)) {
      return {
        checkId,
        status: 'not-applicable',
        confidence: 'high',
        message: 'No server-side code or deployment infrastructure detected',
        findings: [],
      };
    }

    if (isStaticSite(tree, packageJson)) {
      return {
        checkId,
        status: 'not-applicable',
        confidence: 'medium',
        message: 'Static site generator project without server-side routes',
        findings: [],
      };
    }

    const findings = [];

    const infraFiles = tree.filter(p => {
      const lower = p.toLowerCase();
      return /^dockerfile/.test(lower) ||
        /^docker-compose\.(yml|yaml)/.test(lower) ||
        /^wrangler\.(toml|json)/.test(lower) ||
        /^serverless\.(yml|yaml|json|ts)/.test(lower) ||
        /^fly\.toml/.test(lower) ||
        /^Procfile/.test(lower) ||
        /^app\.(ya?ml)/.test(lower) ||
        /^captain-definition/.test(lower) ||
        (/(^|\/)(k8s|kubernetes|helm|deploy|infra)\//.test(p) && /\.(ya?ml|json|toml)$/.test(lower)) ||
        (/\.github\/workflows\//.test(p) && /\.(ya?ml|yaml)$/.test(lower));
    }).slice(0, 10);

    for (const filePath of infraFiles) {
      const content = await files.get(filePath);
      if (!content) continue;
      if (/\b(HEALTHCHECK|healthcheck|health_check|health-path|livenessProbe|readinessProbe|startupProbe)\b/i.test(content) ||
          /['"`](\/health|\/status|\/ready|\/alive|\/ping)['"`]?/i.test(content)) {
        return {
          checkId,
          status: 'pass',
          confidence: 'high',
          message: `Health probe configured in ${filePath}`,
          findings: [{ file: filePath, issue: 'Health check or probe found in deployment config' }],
        };
      }
    }

    if (packageJson?.scripts) {
      for (const [name] of Object.entries(packageJson.scripts)) {
        if (/^(health|healthcheck|status|ping|ready|alive)/i.test(name)) {
          return {
            checkId,
            status: 'pass',
            confidence: 'high',
            message: `Health check script detected: "${name}"`,
            findings: [{ file: 'package.json', issue: `Script "${name}" indicates health endpoint` }],
          };
        }
      }
    }

    const healthLib = findHealthDependency(packageJson);
    if (healthLib) {
      return {
        checkId,
        status: 'pass',
        confidence: 'high',
        message: `Health check library present: ${healthLib}`,
        findings: [{ file: 'package.json', issue: `Uses health library ${healthLib}` }],
      };
    }

    const healthFileRe = /(health|healthcheck|health-check|healthz|status|ready|alive|ping)/i;
    const serverContextRe = /(^|\/)((src\/)?(api|pages\/api|app\/api|app\/health|pages\/health|routes|server\/api|server|middleware|controllers|handlers|backend|workers|netlify\/functions|supabase\/functions|edge-functions))\//i;

    const namedHealthFiles = tree.filter(p =>
      healthFileRe.test(p) &&
      serverContextRe.test(p) &&
      !/\.d\.ts$/.test(p) &&
      !/node_modules/.test(p)
    ).slice(0, 6);

    for (const filePath of namedHealthFiles) {
      const content = await files.get(filePath);
      if (content && content.trim().length > 0) {
        return {
          checkId,
          status: 'pass',
          confidence: 'high',
          message: `Health endpoint file found at ${filePath}`,
          findings: [{ file: filePath, issue: 'Health-related file in API/server directory' }],
        };
      }
    }

    let candidates = tree
      .filter(p => /\.(js|ts|jsx|tsx|mjs|cjs)$/.test(p) && !/\.d\.ts$/.test(p) && !/node_modules/.test(p))
      .map(p => ({ path: p, score: scoreFile(p) }))
      .filter(f => f.score > 0)
      .sort((a, b) => b.score - a.score)
      .slice(0, 10)
      .map(f => f.path);

    if (candidates.length === 0) {
      candidates = tree.filter(p => /^(src\/)?(server|app|index|main)\.(js|ts|mjs|cjs)$/.test(p)).slice(0, 3);
    }

    let foundFile = null;

    for (const filePath of candidates) {
      if (namedHealthFiles.includes(filePath)) continue;
      const content = await files.get(filePath);
      if (!content) {
        findings.push({ file: filePath, issue: 'Could not read file content' });
        continue;
      }

      for (const pattern of HEALTH_PATTERNS) {
        if (pattern.test(content)) {
          foundFile = filePath;
          break;
        }
      }

      if (foundFile) {
        findings.push({ file: filePath, issue: 'Health endpoint pattern matched in source' });
        break;
      } else {
        findings.push({ file: filePath, issue: 'Scanned for health endpoint — none found' });
      }
    }

    if (foundFile) {
      return {
        checkId,
        status: 'pass',
        confidence: 'high',
        message: `Health check endpoint detected in ${foundFile}`,
        findings,
      };
    }

    return {
      checkId,
      status: 'fail',
      confidence: 'high',
      message: 'No health check endpoint or probe detected in this deployed application',
      findings: findings.length > 0 ? findings : [{ file: 'N/A', issue: 'No health endpoint found in scanned files' }],
    };

  } catch (err) {
    console.error(`[health-check] analysis error:`, err);
    return {
      checkId,
      status: 'check-it',
      confidence: 'low',
      message: `Error during health check analysis: ${err.message}`,
      findings: [{ file: 'N/A', issue: `Error: ${err.message}` }],
    };
  }
}
